#include <bits/stdc++.h>
using namespace std;
const int N=5005;
int n,t,s[N],b[N],dp[N][N],ans;
int main()
{
    cin>>n>>t;
    for(int i=1;i<=n;i++) cin>>s[i];
    for(int i=1;i<=n;i++) cin>>b[i];
    memset(dp,128,sizeof(dp));
    dp[0][0]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<t;j++)
        {
            dp[i][j]=max(dp[i-1][j-1]+s[i],dp[i-1][j]-s[i]);
            ans=max(ans,dp[i][j]);
        }
        dp[i][0]=max(dp[i-1][0]-s[i],dp[i-1][t-1]+s[i]+b[i]);
        ans=max(ans,dp[i][0]);
    }
    cout<<ans;
    return 0;
}
